const getFormattedDate = (dateString: string) => {
  return new Date(dateString).toLocaleDateString("en-US", {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
};

const getTotalAmount = (lineItems: any[], taxInPercent: number) => {
  const subTotal: number = lineItems.reduce((total, item) => {
    return total + item.quantity * item.price;
  }, 0);
  const taxAmount = (subTotal * taxInPercent) / 100;
  return { subTotal, taxAmount, total: subTotal + taxAmount };
};

const separateThousands = (amount: number) => {
  return amount.toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
};

const getPuppeteerBrowser = async () => {
  //if browser is not initialized, initialize it and return a new page, else return a new page from the existing browser instance
  if (!browser) {
    browser = await puppeteer.launch({
      headless: true,
      args: ["--no-sandbox", "--disable-setuid-sandbox"],
    });
    return browser.newPage();
  }
  browser = await puppeteer.launch();
  return browser.newPage();
};

