// api/invoices/
//get all invoices
router.get("/", async (_req: Request, res: Response) => {
  try {
    const response = await prisma.invoice.findMany({
      include: {
        client: true,
        lineItems: true,
      },
      orderBy: { createdAt: "desc" },
    });
    res.status(200).json(response);
  } catch (error) {
    res.status(404).json(error);
  }
});

//api/invoices/:id
//get single invoice
router.get("/:id", async (req: Request, res: Response) => {
  const { id } = req.params;
  if (!id)
    return res
      .status(400)
      .json({ error: "Invoice id must be provided in the url params" });
  const response = await prisma.invoice.findUnique({
    where: {
      id: id as string,
    },
    include: {
      client: true,
      lineItems: true,
    },
  });
  //check if invoice was found, if not found response will be null
  if (!response)
    return res
      .status(404)
      .json({ message: "Invoice not found", ok: false, data: response });
  //else if invoice found return it
  return res
    .status(200)
    .json({ message: "Invoice found!", ok: true, data: response });
});

router.get("/downloadPDF/:id", async (req: Request, res: Response) => {
  const { id } = req.params;
  if (!id)
    return res
      .status(400)
      .json({ error: "Invoice id must be provided in the url params" });

  try {
    const response = await prisma.invoice.findUnique({
      where: {
        id: id as string,
      },
      include: {
        client: true,
        lineItems: true,
      },
    });

    if (!response)
      return res
        .status(404)
        .json({ message: "Invoice not found", ok: false, data: response });

    const page = await getPuppeteerBrowser();
    await page.setContent(generateInvoiceHTML(response), {
      waitUntil: "domcontentloaded",
    });
    const pdfBuffer = await page.pdf({ format: "A4", printBackground: true });
    await page.close();
    await browser?.close();

    res.set({
      "Content-Type": "application/pdf",
      "Content-Disposition": `attachment; filename=invoice_${response.id}.pdf`,
    });
    res.send(pdfBuffer).status(200);
  } catch (error) {
    res
      .status(500)
      .json({ error: "An error occurred while generating the PDF" });
  }
});

// api/invoices/create
router.post("/create", async (req: Request, res: Response) => {
  if (!req.body)
    return res
      .json({ error: "Please include a body in your POST req" })
      .status(400);

  const { clientId, dueDate, note, lineItems } = req.body;
  if (!(clientId || dueDate || lineItems.length === 0))
    //check if any compulsory field is empty
    return res.status(400).json({
      error: "All fields mandatory for invoice creation must be provided",
    });

  console.log("req body: ", req.body);
  const invoice = await prisma.invoice.create({
    data: {
      clientId: clientId,
      dueDate: dueDate,
      NoteToClient: note,
      taxInPercent: req.body.taxInPercent || 0,
      status: req.body.status || "PENDING",
      lineItems: {
        create: lineItems.map(
          (item: { name: string; quantity: number; price: number }) => ({
            itemName: item.name,
            quantity: item.quantity,
            price: item.price,
          }),
        ),
      },
    },
  });
  return res
    .json({ message: "Invoice created successfully", invoice })
    .status(201);
});

router.patch("/:id", async (req: Request, res: Response) => {
  const { id } = req.params;
  //check if id is provided in url params
  if (!id)
    return res
      .status(400)
      .json({ error: "Invoice id must be provided in the url params" });
  if (!req.body)
    return res
      .json({ error: "Please include a body in your PATCH req" })
      .status(400);
  const { dueDate, status, taxInPercent, lineItems, note } = req.body;
  try {
    await prisma.invoice.update({
      where: {
        id: id as string,
      },
      data: {
        dueDate: dueDate,
        status: status,
        taxInPercent: taxInPercent,
        NoteToClient: note,
        lineItems: {
          update: lineItems.map(
            (item: {
              id: string;
              name: string;
              quantity: number;
              price: number;
            }) => ({
              where: { id: item.id },
              data: {
                itemName: item.name,
                quantity: item.quantity,
                price: item.price,
              },
            }),
          ),
        },
      },
    });
    return res
      .status(200)
      .json({ message: "Invoice updated successfully", ok: true });
  } catch (error) {
    return res
      .status(500)
      .json({ error: "An error occurred while updating the invoice" });
  }
});

router.delete("/:id", async (req: Request, res: Response) => {
  const { id } = req.params;
  //check if id is provided in url params
  if (!id)
    return res
      .status(400)
      .json({ error: "Invoice id must be provided in the url params" });

  try {
    //first delete lineItems connected to invoice
    await prisma.lineItem.deleteMany({
      where: {
        invoiceId: id as string,
      },
    });
    //then delete the invoice
    await prisma.invoice.delete({
      where: {
        id: id as string,
      },
    });

    return res
      .json({ msg: "Invoice deleted successfully", ok: true })
      .status(200);
  } catch (error) {
    return res
      .status(404)
      .json({ error: "Invoice with the provided id not found", ok: false });
  }
});

export default router;
